CREATE DATABASE IF NOT EXISTS meds_digital_services; USE meds_digital_services; CREATE TABLE roles (id INT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(50) UNIQUE NOT NULL); INSERT INTO roles (name) VALUES ('Admin'),('Programmer'),('Marketer'),('Cyber Security Expert'),('Client'); CREATE TABLE users (id INT PRIMARY KEY AUTO_INCREMENT, first_name VARCHAR(50) NOT NULL, last_name VARCHAR(50) NOT NULL, username VARCHAR(50) UNIQUE NOT NULL, email VARCHAR(100) UNIQUE NOT NULL, phone VARCHAR(20) UNIQUE NOT NULL, password_hash VARCHAR(255) NOT NULL, role_id INT DEFAULT 5, is_active BOOLEAN DEFAULT TRUE, is_verified BOOLEAN DEFAULT FALSE, verification_token VARCHAR(255), reset_token VARCHAR(255), reset_expires DATETIME, last_login DATETIME, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (role_id) REFERENCES roles(id)); CREATE TABLE services (id INT PRIMARY KEY AUTO_INCREMENT, name VARCHAR(100) NOT NULL, description TEXT, price DECIMAL(10,2), duration_days INT); CREATE TABLE projects (id INT PRIMARY KEY AUTO_INCREMENT, title VARCHAR(200) NOT NULL, description TEXT, client_id INT, service_id INT, assigned_to INT, budget DECIMAL(10,2), status ENUM('pending','approved','in_progress','completed','cancelled') DEFAULT 'pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (client_id) REFERENCES users(id), FOREIGN KEY (service_id) REFERENCES services(id), FOREIGN KEY (assigned_to) REFERENCES users(id)); CREATE TABLE messages (id INT PRIMARY KEY AUTO_INCREMENT, sender_id INT, receiver_id INT, project_id INT, message TEXT, is_read BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (sender_id) REFERENCES users(id), FOREIGN KEY (receiver_id) REFERENCES users(id), FOREIGN KEY (project_id) REFERENCES projects(id)); CREATE TABLE notifications (id INT PRIMARY KEY AUTO_INCREMENT, user_id INT, title VARCHAR(200), message TEXT, is_read BOOLEAN DEFAULT FALSE, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (user_id) REFERENCES users(id)); CREATE TABLE payments (id INT PRIMARY KEY AUTO_INCREMENT, project_id INT, user_id INT, amount DECIMAL(10,2), status ENUM('pending','completed','failed') DEFAULT 'pending', created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (project_id) REFERENCES projects(id), FOREIGN KEY (user_id) REFERENCES users(id)); CREATE TABLE reviews (id INT PRIMARY KEY AUTO_INCREMENT, project_id INT, reviewer_id INT, rating INT CHECK (rating BETWEEN 1 AND 5), comment TEXT, created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, FOREIGN KEY (project_id) REFERENCES projects(id), FOREIGN KEY (reviewer_id) REFERENCES users(id));